<template>
  <div @click="emailLink(url, { subject, body })">
    <i class="fas fa-envelope"></i>
  </div>
</template>

<script>
import objectToGetParams from "../utils/objectToGetParams";
export default {
  name: "email-vue",
  methods: {
    emailLink(url, { subject, body }) {
      window.open(
        "mailto:" +
          objectToGetParams({
            subject,
            body: body || url,
          }),
        "__blank"
      );
    },
  },
  props: {
    url: {
      type: String,
      required: true,
    },
    scale: {
      required: false,
      type: String,
    },
    subject: {
      required: false,
      type: String,
    },
    body: {
      required: false,
      type: String,
    },
  },

};
</script>
