<template>
  <div @click="facebookLink(url)">
    <i class="fab fa-facebook"></i>
  </div>
</template>

<script>
import objectToGetParams from "../utils/objectToGetParams";
export default {
  name: "facebook-vue",
  methods: {
    facebookLink(url) {
      window.open(
        `https://www.facebook.com/sharer/sharer.php` +
          objectToGetParams({
            u: url,
          }),
        "__blank"
      );
    },
  },
  props: {
    url: {
      required: true,
      type: String,
    },
    scale: {
      required: false,
      type: String,
    },
  },
};
</script>
