<template>
  <section class="product-list recipes">
    <div class="product-list__container">
      <h1>Список Рецептов</h1>
      <SearchByProducts />
      <FormRecipes />
      <ul class="list-group">
        <h4 v-if="tutorials.length">Список репептов</h4>
        <h4 v-else>Список репептов пуст</h4>
        <li
          class="list-group-item"
          :class="{ active: index == currentIndex }"
          v-for="(tutorial, index) in tutorials"
          :key="index"
          @click="setActiveTutorial(tutorial, index)"
        >
          {{ tutorial.name }}
          <p>{{ tutorial.description }}</p>
          <span>
            {{ tutorial.products }}
          </span>
          <ul class="social-list">
            <div>Рассказать друзьям:</div>
            <li>
              <FacebookVue :url="url"/>
            </li>
            <li>
              <EmailVue :url="tutorial.name" :body="tutorial.steps"/>
            </li>
            <li>
              <TelegramVue :url="tutorial.name" :text="tutorial.steps"/>
            </li>
          </ul>
        </li>
      </ul>
      <div class="modal">
        <div v-if="currentTutorial">
          <ReceptDetails
            :tutorial="currentTutorial"
            @refreshList="refreshList"
          />
        </div>
      </div>
      <button class="btn-danger" @click="removeAllTutorials">
        Удалить все
      </button>
    </div>
  </section>
</template>

<script>
import TutorialDataService from "@/services/ReciepesDataService";
import ReceptDetails from "@/components/Reciepes/ReceptDetails";
import FormRecipes from "@/components/Reciepes/FormRecipes";
import "@/assets/productList.scss";
import SearchByProducts from "./SearchByProducts.vue";
import FacebookVue from "../Facebook.vue";
import EmailVue from "../Email.vue";
import TelegramVue from "../Telegram.vue";

export default {
  name: "tutorials-list",
  components: {
    ReceptDetails,
    FormRecipes,
    SearchByProducts,
    FacebookVue,
    EmailVue,
    TelegramVue,
  },
  data() {
    return {
      tutorials: [],
      currentTutorial: null,
      currentIndex: -1,
      opened: false,
      url: 'https://google.by',
      body: [],
      text: [],
    };
  },
  methods: {
    onDataChange(items) {
      let _tutorials = [];

      items.forEach((item) => {
        let key = item.key;
        let data = item.val();
        _tutorials.push({
          key: key,
          name: data.name,
          description: data.description,
          steps: data.steps,
          products: data.products,
        });
      });

      this.tutorials = _tutorials;
    },

    refreshList() {
      this.currentTutorial = null;
      this.currentIndex = -1;
    },

    setActiveTutorial(tutorial, index) {
      this.currentTutorial = tutorial;
      this.currentIndex = index;
    },

    removeAllTutorials() {
      TutorialDataService.deleteAll()
        .then(() => {
          this.refreshList();
        })
        .catch((e) => {
          console.log(e);
        });
    },
    getData(tutorial){
       return tutorial.description
    },
    currentDate() {
      let date = new Date();
      return (date = date.toLocaleDateString());
    },
  },
  mounted() {
    TutorialDataService.getAll().on("value", this.onDataChange);
  },
  beforeUnmount() {
    TutorialDataService.getAll().off("value", this.onDataChange);
  },
};
</script>

<style>
.list {
  text-align: left;
  max-width: 750px;
  margin: auto;
}
</style>
