import firebase from "../firebase";

const db = firebase.ref("/Recipes");

class RecipesDataService {
  getAll() {
    return db;
  }

  create(recept) {
    return db.push(recept);
  }
  search(recept, products){
    return db.equalTo(products)
  }

  update(key, value) {
    return db.child(key).update(value);
  }

  delete(key) {
    return db.child(key).remove();
  }

  deleteAll() {
    return db.remove();
  }
}

export default new RecipesDataService();
